<?php require_once "config/database.php"; require_once "includes/session.php"; include "includes/header.php";$id=$_GET['id']??0;if(isset($_POST['favorite'])&&isLoggedIn()){try{$conn->prepare("INSERT INTO favorites(user_id,room_id) VALUES(?,?)")->execute([$_SESSION['user_id'],$id]);}catch(Exception $e){}}if(isset($_POST['review'])&&isLoggedIn()){$conn->prepare("INSERT INTO reviews(user_id,room_id,rating,comment) VALUES(?,?,?,?)")->execute([$_SESSION['user_id'],$id,$_POST['rating'],$_POST['comment']]);}$stmt=$conn->prepare("SELECT * FROM rooms WHERE room_id=?");$stmt->execute([$id]);$room=$stmt->fetch(PDO::FETCH_ASSOC);$imgs=$conn->prepare("SELECT * FROM room_images WHERE room_id=?");$imgs->execute([$id]);$imgs=$imgs->fetchAll(PDO::FETCH_ASSOC);$reviews=$conn->prepare("SELECT reviews.*,users.full_name FROM reviews JOIN users ON reviews.user_id=users.user_id WHERE room_id=? AND reviews.status='Visible'");$reviews->execute([$id]);$reviews=$reviews->fetchAll(PDO::FETCH_ASSOC);?>
<div class="container"><div class="card"><img src="<?=e($room['image_url'])?>" style="height:360px"><div class="card-body"><h1><?=e($room['room_name'])?></h1><p><?=e($room['floor'])?> • <?=e($room['room_type'])?> • Good for <?=$room['capacity']?> tenant/s</p><p><?=e($room['description'])?></p><div class="price">₱<?=number_format($room['price'],2)?> / month</div><h3>Amenities</h3><?php foreach(explode(',',$room['amenities']) as $a):?><span class="tag"><?=e(trim($a))?></span><?php endforeach;?><h3>House Rules</h3><p><?=e($room['rules'])?></p><h3>Gallery</h3><div class="gallery"><?php foreach($imgs as $im):?><img src="<?=e($im['image_url'])?>"><?php endforeach;?></div><?php if(isLoggedIn()):?><form method="POST"><button name="favorite" class="btn">Add to Favourites</button></form><?php endif;?><?php if($room['status']==='Available'):?><a class="btn gold" href="reserve.php?room_id=<?=$room['room_id']?>">Reserve Now</a><?php endif;?></div></div><div class="form-card"><h2>Review Room</h2><?php if(isLoggedIn()):?><form method="POST"><select name="rating"><option value="5">5 Stars</option><option value="4">4 Stars</option><option value="3">3 Stars</option><option value="2">2 Stars</option><option value="1">1 Star</option></select><textarea name="comment" placeholder="Comment"></textarea><button name="review" class="btn">Submit Review</button></form><?php else:?><p>Login to review.</p><?php endif;?></div><div class="table-wrap"><h2>Reviews</h2><?php foreach($reviews as $rv):?><p><b><?=e($rv['full_name'])?></b> <span class="stars">⭐ <?=$rv['rating']?></span><br><?=e($rv['comment'])?></p><hr><?php endforeach;?></div></div><?php include "includes/footer.php";?>
